function getAuthCode(authUri) {
    const authParams = Object.entries({
        response_type: 'code', // request auth code only, access token is not requested!
        client_id: 'YOUR_CLIENTID',
        redirect_uri: 'http://localhost:3001' // must match the redirect URI you have configured in your OAuth application on https://accounts.google.com/o/oauth2/auth
    }).reduce((prev, curr) => {
        return `${curr[0]}=${encodeURIComponent(curr[1])}${prev ? '&' + prev : ''}`;
    }, '');

    const authRequest = `${authUri}?${authParams}`; // the request to OAuth provider

    window.location.assign(authRequest);
}